// src/pages/Login.jsx

import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("customer");

  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/login",
        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");

      }

    } catch (err) {

      alert("Invalid Credentials");

    }
  };

  return (

    <div style={styles.page}>

      {/* LEFT SIDE */}

      <div style={styles.left}>

        <div style={styles.orangeBox}></div>

        <div style={styles.content}>

          <h1 style={styles.brand}>
            DailyMajdoor
          </h1>

          <h2 style={styles.heading}>
            Hire Workers
            <br />
            The Smart Way
          </h2>

          <p style={styles.text}>
            Fast, secure and easy worker hiring platform.
          </p>

        </div>

      </div>

      {/* RIGHT SIDE */}

      <div style={styles.right}>

        <div style={styles.card}>

          <div style={styles.topLine}></div>

          <h2 style={styles.loginTitle}>
            Login
          </h2>

          <p style={styles.sub}>
            Welcome back 👋
          </p>

          <form onSubmit={loginUser}>

            <select
              style={styles.input}
              value={role}
              onChange={(e) =>
                setRole(e.target.value)
              }
            >

              <option value="customer">
                Customer
              </option>

              <option value="labour">
                Labour
              </option>

            </select>

            <input
              type="email"
              placeholder="Email"
              style={styles.input}
              value={email}
              onChange={(e) =>
                setEmail(e.target.value)
              }
            />

            <input
              type="password"
              placeholder="Password"
              style={styles.input}
              value={password}
              onChange={(e) =>
                setPassword(e.target.value)
              }
            />

            <button style={styles.button}>
              Login
            </button>

          </form>

          <p style={styles.bottomText}>

            Don't have account?

            <span
              style={styles.link}
              onClick={() =>
                nav("/register")
              }
            >
              Register
            </span>

          </p>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    display: "flex",
    fontFamily: "Arial",
    background: "#f8fafc"
  },

  /* LEFT */

  left: {
    width: "50%",
    background: "#111827",
    position: "relative",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    overflow: "hidden"
  },

  orangeBox: {
    position: "absolute",
    width: "420px",
    height: "420px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    borderRadius: "40px",
    transform: "rotate(45deg)",
    opacity: 0.15
  },

  content: {
    position: "relative",
    zIndex: 2,
    color: "white",
    textAlign: "center"
  },

  brand: {
    fontSize: "48px",
    marginBottom: "20px"
  },

  heading: {
    fontSize: "54px",
    lineHeight: "70px",
    marginBottom: "20px"
  },

  text: {
    fontSize: "18px",
    color: "#d1d5db"
  },

  /* RIGHT */

  right: {
    width: "50%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  card: {
    width: "380px",
    background: "white",
    borderRadius: "24px",
    padding: "40px",
    boxShadow:
      "0 10px 40px rgba(0,0,0,0.08)",
    position: "relative"
  },

  topLine: {
    position: "absolute",
    top: 0,
    left: 0,
    width: "100%",
    height: "6px",
    borderTopLeftRadius: "24px",
    borderTopRightRadius: "24px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)"
  },

  loginTitle: {
    fontSize: "34px",
    marginBottom: "10px",
    color: "#111827"
  },

  sub: {
    color: "#6b7280",
    marginBottom: "30px"
  },

  input: {
    width: "100%",
    padding: "15px",
    marginBottom: "18px",
    borderRadius: "12px",
    border: "1px solid #e5e7eb",
    background: "#f9fafb",
    boxSizing: "border-box",
    outline: "none",
    fontSize: "14px"
  },

  button: {
    width: "100%",
    padding: "15px",
    border: "none",
    borderRadius: "12px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    fontWeight: "bold",
    fontSize: "15px",
    cursor: "pointer",
    marginTop: "5px"
  },

  bottomText: {
    textAlign: "center",
    marginTop: "24px",
    color: "#6b7280",
    fontSize: "14px"
  },

  link: {
    color: "#f97316",
    marginLeft: "5px",
    cursor: "pointer",
    fontWeight: "bold"
  }

};
